use std::fmt::Write;

use proc_macro2::TokenStream;
use quote::{format_ident, quote};
use rust_format::{Formatter, RustFmt};
use weedle::Definition::*;
use weedle::argument::Argument::Single;
use weedle::interface::InterfaceMember;
use weedle::types::ReturnType;

const PREAMBLE: &str = r#"// DO NOT MODIFY!
// This file is generated by tools/glean-sys-parser.
// Run `cargo run -p glean-sys-parser glean-core/src/glean.udl` to regenerate it.

struct Rate {
    numerator: i32,
    denominator: i32,
}

type JsonValue = String;
struct RecordedEvent {
    timestamp: u64,
    category: String,
    name: String,
    extra: Option<::std::collections::HashMap<String, String>>,
}

struct Datetime {
    year: i32,
    month: u32,
    day: u32,
    hour: u32,
    minute: u32,
    second: u32,
    nanosecond: u32,
    offset_seconds: i32,
}

struct DistributionData {
    values: ::std::collections::HashMap<i64, i64>,
    sum: i64,
    count: i64,
}

struct TimerId {
    id: u64,
}

enum ErrorType {
    InvalidValue,
    InvalidLabel,
    InvalidState,
    InvalidOverflow,
}

fn main() {}
"#;

fn resolve_builtin_type(name: &str) -> Option<TokenStream> {
    match name {
        "string" => Some(quote! { String }),
        "bytes" => Some(quote! { Vec<u8> }),
        "u8" => Some(quote! { u8 }),
        "i8" => Some(quote! { i8 }),
        "u16" => Some(quote! { u16 }),
        "i16" => Some(quote! { i16 }),
        "u32" => Some(quote! { u32 }),
        "i32" => Some(quote! { i32 }),
        "u64" => Some(quote! { u64 }),
        "i64" => Some(quote! { i64 }),
        "f32" => Some(quote! { f32 }),
        "f64" => Some(quote! { f64 }),
        "void" => Some(quote! { () }),
        _ => None,
    }
}

trait TypeResolver {
    fn resolve(&self) -> TokenStream;
}

impl TypeResolver for &weedle::types::Type<'_> {
    fn resolve(&self) -> TokenStream {
        (*self).resolve()
    }
}

impl TypeResolver for weedle::types::Type<'_> {
    fn resolve(&self) -> TokenStream {
        match self {
            weedle::types::Type::Single(t) => match t {
                weedle::types::SingleType::Any(_) => panic!("no support for `any` types"),
                weedle::types::SingleType::NonAny(t) => t.resolve(),
            },
            weedle::types::Type::Union(_) => panic!("no support for union types yet"),
        }
    }
}

impl TypeResolver for weedle::types::NonAnyType<'_> {
    fn resolve(&self) -> TokenStream {
        match self {
            weedle::types::NonAnyType::Boolean(t) => t.resolve(),
            weedle::types::NonAnyType::Identifier(t) => t.resolve(),
            weedle::types::NonAnyType::Integer(t) => t.resolve(),
            weedle::types::NonAnyType::FloatingPoint(t) => t.resolve(),
            weedle::types::NonAnyType::Sequence(t) => t.resolve(),
            weedle::types::NonAnyType::RecordType(t) => t.resolve(),
            _ => panic!("no support for type {:?}", self),
        }
    }
}

impl<T: TypeResolver> TypeResolver for weedle::types::MayBeNull<T> {
    fn resolve(&self) -> TokenStream {
        let type_ = self.type_.resolve();
        match self.q_mark {
            None => type_,
            Some(_) => {
                quote! { Option<#type_> }
            }
        }
    }
}

impl TypeResolver for weedle::types::IntegerType {
    fn resolve(&self) -> TokenStream {
        panic!(
            "WebIDL integer types not implemented ({:?}); consider using u8, u16, u32 or u64",
            self
        )
    }
}

impl TypeResolver for weedle::types::FloatingPointType {
    fn resolve(&self) -> TokenStream {
        match self {
            weedle::types::FloatingPointType::Float(t) => t.resolve(),
            weedle::types::FloatingPointType::Double(t) => t.resolve(),
        }
    }
}

impl TypeResolver for weedle::types::SequenceType<'_> {
    fn resolve(&self) -> TokenStream {
        let t = self.generics.body.as_ref().resolve();
        quote! { Vec<#t> }
    }
}

impl TypeResolver for weedle::types::RecordKeyType<'_> {
    fn resolve(&self) -> TokenStream {
        use weedle::types::RecordKeyType::*;
        match self {
            Byte(_) | USV(_) => panic!(
                "WebIDL Byte or USV string type not implemented ({self:?}); \
                 consider using a string",
            ),
            DOM(_) => quote! { String },
            NonAny(t) => t.resolve(),
        }
    }
}

impl TypeResolver for weedle::types::RecordType<'_> {
    fn resolve(&self) -> TokenStream {
        let key_type = self.generics.body.0.resolve();
        let value_type = self.generics.body.2.resolve();

        quote! { ::std::collections::HashMap<#key_type, #value_type> }
    }
}

impl TypeResolver for weedle::common::Identifier<'_> {
    fn resolve(&self) -> TokenStream {
        match resolve_builtin_type(self.0) {
            Some(type_) => type_,
            None => {
                let ident = format_ident!("{}", self.0);
                quote! { #ident }
            }
        }
    }
}

impl TypeResolver for weedle::term::Boolean {
    fn resolve(&self) -> TokenStream {
        quote! { bool }
    }
}

impl TypeResolver for weedle::types::FloatType {
    fn resolve(&self) -> TokenStream {
        if self.unrestricted.is_some() {
            panic!("we don't support `unrestricted float`");
        }
        quote! { f32 }
    }
}

impl TypeResolver for weedle::types::DoubleType {
    fn resolve(&self) -> TokenStream {
        if self.unrestricted.is_some() {
            panic!("we don't support `unrestricted double`");
        }
        quote! { f64 }
    }
}

fn return_type(typ: ReturnType) -> TokenStream {
    let ReturnType::Type(typ) = typ else {
        panic!("can't handle undefined return type")
    };
    let ret = typ.resolve();
    quote! { -> #ret }
}

fn main() {
    let file = std::env::args().skip(1).next().unwrap();
    let content = std::fs::read_to_string(&file).unwrap();
    let parsed = weedle::parse(&content).unwrap();

    let mut tokens = vec![];

    for elem in parsed {
        let Interface(iface) = elem else { continue };
        let ident = iface.identifier;
        if !ident.0.ends_with("Metric") {
            continue;
        }

        let ident = format_ident!("{}", ident.0);
        tokens.push(quote! {
            struct #ident {
                handle: u64
            }
        });

        let mut fns = vec![];
        let members = iface.members;
        for member in members.body {
            match member {
                InterfaceMember::Constructor(_ctor) => {
                    fns.push(quote! {
                        fn new() -> Self {
                            todo!()
                        }
                    });
                }
                InterfaceMember::Operation(op) => {
                    let Some(ident) = op.identifier else {
                        panic!("no identifier for op!")
                    };
                    let fn_ident = format_ident!("{}", ident.0);
                    let ret_type = return_type(op.return_type);

                    let args = op.args.body.list;
                    let mut fn_args = Vec::with_capacity(args.len());

                    for arg in args {
                        let Single(arg) = arg else { continue };
                        let arg_name = format_ident!("{}", arg.identifier.0);
                        let arg_type = arg.type_.type_.resolve();
                        fn_args.push(quote! { #arg_name: #arg_type });
                    }
                    fns.push(quote! {
                        fn #fn_ident(&self, #(#fn_args),*) #ret_type {
                            todo!()
                        }
                    });
                }
                _ => todo!(),
            }
        }

        tokens.push(quote! {
            impl #ident {
                #(#fns)*
            }
        });
    }

    let mut code = String::new();
    for token in tokens {
        writeln!(&mut code, "{token}").unwrap();
    }

    println!("{PREAMBLE}");
    let code = RustFmt::default().format_str(code).unwrap();
    println!("{code}");
}
